const raw = $input.item.json;
const hoje = new Date();
const diaSemana = hoje.getDay();
let alertas = [];
let resumo = [];
let lembreteDomingo = '';
const MSGS = {
  INGRID: {
    silencio:  'Ingrid, tudo bem? Estou por aqui se precisar de algo. \ud83d\ude42',
    reativacao: 'Ingrid, estou por aqui. Como est\u00e1 o estudo?',
    relatorio:  'Ingrid, semana encerrada! Me conta: quantas quest\u00f5es voc\u00ea respondeu essa semana? Quero atualizar o seu relat\u00f3rio de progresso. \ud83d\udcca'
  },
  VALDECE: {
    reativacao: 'Dr. Valdece, tudo bem? Passando para saber como est\u00e1 sendo a experi\u00eancia com o sistema.'
  }
};
function getMsgAlerta(cliente, diasSem) {
  const c = cliente.toUpperCase();
  if (c === 'INGRID') return diasSem >= 5 ? MSGS.INGRID.reativacao : MSGS.INGRID.silencio;
  if (c === 'VALDECE') return MSGS.VALDECE.reativacao;
  return null;
}
try {
  const content = raw.content ? Buffer.from(raw.content.replace(/\n/g,''),'base64').toString('utf8') : null;
  if (!content) throw new Error('WIP_BOARD vazio');
  const wip = JSON.parse(content);
  const board = wip.board || {};
  ['build','check','retainer'].forEach(function(col) {
    (board[col]||[]).forEach(function(p) {
      const threshold = parseInt(p.churn_watch_threshold) || 3;
      const ultimoContato = p.ultimo_contato_cliente;
      if (!ultimoContato) return;
      const dtUltimo = new Date(ultimoContato);
      const diasSem = Math.floor((hoje - dtUltimo) / (1000*60*60*24));
      const status = diasSem >= threshold ? 'ALERTA' : 'OK';
      resumo.push(p.cliente + ': ' + diasSem + 'd (threshold ' + threshold + 'd) -- ' + status);
      if (diasSem >= threshold) {
        alertas.push({ cliente: p.cliente, diasSem: diasSem, threshold: threshold,
          ultimoContato: ultimoContato, status: col.toUpperCase(),
          msgSugerida: getMsgAlerta(p.cliente, diasSem) });
      }
      if (diaSemana === 0 && p.cliente.toUpperCase() === 'INGRID') {
        lembreteDomingo = MSGS.INGRID.relatorio;
      }
    });
  });
} catch(e) {
  resumo.push('ERRO ao ler WIP_BOARD: ' + e.message);
}
const dataHora = hoje.toISOString().replace('T',' ').slice(0,16) + ' UTC';
let textoResumo = 'ChurnWatch ' + dataHora + '\n\n' + resumo.join('\n');
if (lembreteDomingo) {
  textoResumo += '\n\n\ud83d\udccb Domingo -- mensagem sugerida para Ingrid:\n' + lembreteDomingo;
}
let textoAlerta = '';
if (alertas.length > 0) {
  const linhas = alertas.map(function(a) {
    let txt = '\u26a0\ufe0f ' + a.cliente + ' -- ' + a.diasSem + 'd sem contato (limite: ' + a.threshold + 'd)\nUltimo: ' + a.ultimoContato + ' | ' + a.status;
    if (a.msgSugerida) txt += '\n\n\ud83d\udcac Mensagem sugerida (copiar e enviar no WhatsApp):\n' + a.msgSugerida;
    txt += '\n\nApos enviar: /ok ' + a.cliente + ' neste chat';
    return txt;
  });
  textoAlerta = 'CHURNWATCH -- ALERTA\n\n' + linhas.join('\n\n---\n\n');
}
return [{ json: { textoResumo: textoResumo, textoAlerta: textoAlerta, temAlerta: alertas.length > 0, chatId: $env.TELEGRAM_CHAT_ID || '8895733647' } }];
